// ─── LLM Monitor: Build Daily Digest Email ───────────────────────────────

// 1. Grab upstream node outputs
const collectResult = $('Run Collection').item.json;
const newModelsData = $('Get New Models').item.json;
const allRecs       = $('Get All Recommendations').item.json;

// 2. Extract key values
const newModels   = newModelsData.models || [];
const totalModels = newModelsData.total  || 0;
const newCount    = newModels.length;
const date      = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const dateShort = new Date().toLocaleDateString('en-US', { month:'short', day:'numeric' });

// 3. Collection status table rows
const statusRows = Object.entries(collectResult.results || {}).map(([k, v]) => {
  const ok  = v === 'ok';
  const bg  = ok ? '#dcfce7' : '#fee2e2';
  const fg  = ok ? '#166534' : '#991b1b';
  const txt = ok ? '&#10003; OK' : '&#10007; ' + v;
  return `<tr><td style='padding:6px 12px;font-size:13px;color:#475569;border-bottom:1px solid #f1f5f9;'>${k.replace(/_/g,' ')}</td><td style='padding:6px 12px;border-bottom:1px solid #f1f5f9;'><span style='background:${bg};color:${fg};padding:2px 8px;border-radius:9999px;font-size:11px;font-weight:600;'>${txt}</span></td></tr>`;
}).join('');

// 4. New models list items
const newModelItems = newModels.slice(0, 15).map(m =>
  `<li style='margin-bottom:4px;'><strong>${m.name}</strong> <span style='color:#64748b;font-size:12px;'>· ${m.provider || '—'} · ${m.license_type || 'unknown'} · ${m.source}</span></li>`
).join('');

// 5. Per-profile recommendation tables
const PROFILE_LABELS = {
  coding:            'Coding / Dev',
  reasoning:         'Reasoning / Analysis',
  rag_long_context:  'Long Context RAG',
  minimum_cost:      'Minimum Cost',
  enterprise_agents: 'Enterprise Agents'
};
const MEDALS = ['#1', '#2', '#3'];

const recSections = Object.entries(allRecs).map(([profile, data]) => {
  const results = (data.results || []).slice(0, 3);
  const rows = results.map((m, i) =>
    `<tr><td style='padding:8px 12px;font-size:13px;border-bottom:1px solid #f8fafc;'>${MEDALS[i]} <strong>${m.name}</strong></td><td style='padding:8px 12px;font-size:13px;color:#0891b2;font-weight:600;border-bottom:1px solid #f8fafc;'>${(m.score||0).toFixed(3)}</td><td style='padding:8px 12px;font-size:11px;color:#64748b;border-bottom:1px solid #f8fafc;'>${m.provider || '—'}</td></tr>`
  ).join('');
  const label = PROFILE_LABELS[profile] || profile;
  return `<h3 style='margin:20px 0 8px;font-size:12px;color:#0891b2;text-transform:uppercase;letter-spacing:1px;'>${label}</h3><table style='width:100%;border-collapse:collapse;background:#f8fafc;border-radius:6px;overflow:hidden;margin-bottom:4px;'>${rows}</table>`;
}).join('');

// 6. Conditional new-models banner
const newModelsSection = newCount > 0
  ? `<div style='background:#ecfeff;border-radius:10px;padding:20px;margin-bottom:24px;border:1px solid #a5f3fc;'><h2 style='font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#0891b2;margin:0 0 12px;'>New Models Detected (${newCount})</h2><ul style='margin:0;padding-left:18px;font-size:13px;color:#475569;line-height:1.8;'>${newModelItems}</ul></div>`
  : '';

// 7. KPI background colors (dynamic)
const newBg     = newCount > 0 ? '#ecfeff' : '#f8fafc';
const newBorder = newCount > 0 ? '#a5f3fc' : '#e2e8f0';
const newColor  = newCount > 0 ? '#0891b2' : '#0f172a';

// 8. Email subject
const newTag = newCount > 0 ? `${newCount} new model${newCount > 1 ? 's' : ''} - ` : '';
const subject = `LLM Monitor - ${newTag}Daily Digest ${dateShort}`;

// 9. Full HTML body
const html = `<!DOCTYPE html><html><head><meta charset='utf-8'></head><body style='margin:0;padding:0;background:#f1f5f9;font-family:-apple-system,BlinkMacSystemFont,sans-serif;'><div style='max-width:680px;margin:24px auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.08);'><div style='background:linear-gradient(135deg,#0c1429 0%,#0f2a4a 100%);padding:32px 36px;'><div style='font-size:11px;letter-spacing:3px;color:#22d3ee;font-weight:700;text-transform:uppercase;margin-bottom:4px;'>EPINEON AI</div><div style='font-size:20px;font-weight:700;color:#fff;margin-bottom:4px;'>LLM Monitor - Daily Digest</div><div style='font-size:13px;color:#64748b;'>${date}</div></div><div style='padding:28px 36px;'><div style='display:flex;gap:12px;margin-bottom:24px;'><div style='flex:1;background:#f8fafc;border-radius:10px;padding:16px;text-align:center;border:1px solid #e2e8f0;'><div style='font-size:28px;font-weight:700;color:#0f172a;'>${totalModels}</div><div style='font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;margin-top:2px;'>Models</div></div><div style='flex:1;background:${newBg};border-radius:10px;padding:16px;text-align:center;border:1px solid ${newBorder};'><div style='font-size:28px;font-weight:700;color:${newColor};'>${newCount}</div><div style='font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;margin-top:2px;'>New</div></div><div style='flex:1;background:#f8fafc;border-radius:10px;padding:16px;text-align:center;border:1px solid #e2e8f0;'><div style='font-size:28px;font-weight:700;color:#0f172a;'>5</div><div style='font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;margin-top:2px;'>Profiles</div></div></div><h2 style='font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#94a3b8;margin:0 0 10px;'>Collection Status</h2><table style='width:100%;border-collapse:collapse;margin-bottom:24px;border:1px solid #f1f5f9;border-radius:8px;overflow:hidden;'>${statusRows}</table>${newModelsSection}<h2 style='font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#94a3b8;margin:0 0 16px;'>Top Recommendations - AHP+TOPSIS</h2>${recSections}<div style='margin-top:28px;padding-top:20px;border-top:1px solid #f1f5f9;text-align:center;font-size:11px;color:#94a3b8;'>EPINEON AI - LLM Monitor - PFE 2026 - ESITH<br><a href='http://localhost:3000' style='color:#0891b2;text-decoration:none;'>View Dashboard</a></div></div></div></body></html>`;

return [{ json: { subject, html } }];
